const crypto = require('crypto');
const fs = require('fs');

const brokerBaseUrl = 'http://broker:8090';
const env = process.env;
const uri = 's3://' + env.BUCKET_NAME + '/' + env.OBJECT_KEY;
const mimeType = env.OBJECT_KEY.endsWith('.mp4') ? 'video/mp4' : 'application/octet-stream';
const checksumSha256 = crypto.createHash('sha256').update(fs.readFileSync(env.OUTPUT_PATH)).digest('hex');
const workflowEventHash = crypto.createHash('sha256').update(env.WORKFLOW_EVENT_ID + ':' + env.RUN_ID + ':' + uri).digest('hex');
const artifactEventHash = crypto.createHash('sha256').update(env.ARTIFACT_EVENT_ID + ':' + env.RUN_ID + ':' + uri).digest('hex');

async function post(path, payload) {
  const response = await fetch(brokerBaseUrl + path, {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify(payload),
  });
  const body = await response.text();
  if (!response.ok) {
    throw new Error(path + ' ' + response.status + ' ' + body);
  }
  return body ? JSON.parse(body) : {};
}

async function main() {
